{
    "level": "A1–A2",
    "intro": "In the past, the verb <strong>to be</strong> has the forms <strong>was / were</strong>. We use them when we talk about <strong>what someone was like</strong>, <strong>where someone was</strong>, or <strong>what was true before</strong>.",
    "rules": [
        {
            "label": "was",
            "color": "emerald",
            "text": "With <strong>I / he / she / it</strong>, use <strong>was</strong>.",
            "example": "I was tired. / She was at home."
        },
        {
            "label": "were",
            "color": "blue",
            "text": "With <strong>you / we / they</strong>, use <strong>were</strong>.",
            "example": "You were right. / They were late."
        },
        {
            "label": "Questions without did",
            "color": "amber",
            "text": "In questions with <strong>to be</strong>, you do not need <strong>did</strong>.",
            "example": "Was he busy? / Were they ready?"
        }
    ]
}

{
    "title": "1. Forms of was / were",
    "intro": "Start with the two main forms and remember which subjects they go with.",
    "items": [
        {
            "label": "I / He / She / It",
            "title": "was",
            "subtitle": "I was happy. / It was cold."
        },
        {
            "label": "You / We / They",
            "title": "were",
            "subtitle": "You were late. / They were happy."
        },
        {
            "label": "Negative",
            "title": "was not / were not",
            "subtitle": "wasn't / weren't are the short forms."
        },
        {
            "label": "Pattern",
            "title": "Subject + was / were",
            "subtitle": "She was at home. / We were ready."
        }
    ]
}

{
    "title": "2. Negatives",
    "intro": "To make a negative, add <strong>not</strong> after <strong>was / were</strong>.",
    "rows": [
        {
            "en": "I was at home.",
            "ua": "I wasn't at home.",
            "note": "wasn't = was not"
        },
        {
            "en": "She was tired.",
            "ua": "She was not tired.",
            "note": "The full form sounds clearer or stronger."
        },
        {
            "en": "They were late.",
            "ua": "They weren't late.",
            "note": "weren't = were not"
        }
    ],
    "warning": "📌 With <strong>to be</strong> in the past, do not add <strong>didn't</strong>."
}

{
    "title": "3. Questions",
    "sections": [
        {
            "label": "Was + I / he / she / it",
            "color": "emerald",
            "description": "With <strong>I / he / she / it</strong>, start the question with <strong>was</strong>.",
            "examples": [
                {
                    "en": "Was he at work yesterday?",
                    "ua": "Was he at work yesterday?"
                },
                {
                    "en": "Was it difficult?",
                    "ua": "Was it difficult?"
                }
            ]
        },
        {
            "label": "Were + you / we / they",
            "color": "blue",
            "description": "With <strong>you / we / they</strong>, put <strong>were</strong> before the subject.",
            "examples": [
                {
                    "en": "Were you busy?",
                    "ua": "Were you busy?"
                },
                {
                    "en": "Were they ready?",
                    "ua": "Were they ready?"
                }
            ]
        },
        {
            "label": "Without did",
            "color": "amber",
            "description": "With <strong>to be</strong>, we simply invert the words: <strong>was / were + subject</strong>.",
            "examples": [
                {
                    "en": "She was at home. → Was she at home?",
                    "ua": "Turn the statement into a question without did."
                },
                {
                    "en": "Where were you yesterday?",
                    "ua": "In wh-questions, was / were still comes before the subject."
                }
            ]
        }
    ]
}

{
    "title": "4. Short answers",
    "intro": "In a short answer, repeat <strong>was</strong> or <strong>were</strong>.",
    "rows": [
        {
            "en": "Were you at home?",
            "ua": "Yes, I was. / No, I wasn't.",
            "note": "After Were you...?, we answer with I was / I wasn't."
        },
        {
            "en": "Was she ready?",
            "ua": "Yes, she was. / No, she wasn't.",
            "note": "was → she was / she wasn't"
        },
        {
            "en": "Were they late?",
            "ua": "Yes, they were. / No, they weren't.",
            "note": "were → they were / they weren't"
        }
    ],
    "warning": "📌 A short answer repeats <strong>was / were</strong>, not <strong>did</strong>."
}

{
    "title": "5. Common mistakes",
    "items": [
        {
            "label": "Mistake 1",
            "color": "rose",
            "title": "Mixing up was and were.",
            "wrong": "❌ They was late.",
            "right": "✅ <span class=\"font-mono\">They were late.</span>"
        },
        {
            "label": "Mistake 2",
            "color": "amber",
            "title": "Adding did to to be.",
            "wrong": "❌ Did she was at home?",
            "right": "✅ <span class=\"font-mono\">Was she at home?</span>"
        },
        {
            "label": "Mistake 3",
            "color": "sky",
            "title": "Using the wrong short answer.",
            "wrong": "❌ Yes, they was.",
            "right": "✅ <span class=\"font-mono\">Yes, they were.</span>"
        }
    ]
}

